// ==================== Configuration ====================

@Configuration
class KafkaProducerConfig {

    @Value("${kafka.bootstrap.servers:localhost:9092}")
    private String bootstrapServers;

    @Value("${kafka.security.protocol:SASL_SSL}")
    private String securityProtocol;

    @Value("${kafka.sasl.mechanism:SCRAM-SHA-512}")
    private String saslMechanism;

    @Value("${kafka.sasl.jaas.config:}")
    private String saslJaasConfig;

    @Value("${kafka.ssl.truststore.location:}")
    private String sslTruststoreLocation;

    @Value("${kafka.ssl.truststore.password:}")
    private String sslTruststorePassword;

    @Value("${kafka.ssl.keystore.location:}")
    private String sslKeystoreLocation;

    @Value("${kafka.ssl.keystore.password:}")
    private String sslKeystorePassword;

    @Value("${kafka.ssl.endpoint.identification.algorithm:https}")
    private String sslEndpointIdentificationAlgorithm;

    @Bean
    public KafkaProducer<String, String> kafkaProducer() {
        Properties props = new Properties();
        props.put(ProducerConfig.BOOTSTRAP_SERVERS_CONFIG, bootstrapServers);
        props.put(ProducerConfig.KEY_SERIALIZER_CLASS_CONFIG, StringSerializer.class.getName());
        props.put(ProducerConfig.VALUE_SERIALIZER_CLASS_CONFIG, StringSerializer.class.getName());

        // Idempotent producer for exactly-once semantics
        props.put(ProducerConfig.ENABLE_IDEMPOTENCE_CONFIG, true);
        props.put(ProducerConfig.ACKS_CONFIG, "all");
        props.put(ProducerConfig.RETRIES_CONFIG, 3);
        props.put(ProducerConfig.MAX_IN_FLIGHT_REQUESTS_PER_CONNECTION, 5);

        // Security: SASL_SSL
        props.put("security.protocol", securityProtocol);

        if (!saslMechanism.isEmpty()) {
            props.put("sasl.mechanism", saslMechanism);
        }
        if (!saslJaasConfig.isEmpty()) {
            props.put("sasl.jaas.config", saslJaasConfig);
        }

        // SSL/TLS configuration
        if (!sslTruststoreLocation.isEmpty()) {
            props.put("ssl.truststore.location", sslTruststoreLocation);
            props.put("ssl.truststore.password", sslTruststorePassword);
        }
        if (!sslKeystoreLocation.isEmpty()) {
            props.put("ssl.keystore.location", sslKeystoreLocation);
            props.put("ssl.keystore.password", sslKeystorePassword);
        }
        props.put("ssl.endpoint.identification.algorithm", sslEndpointIdentificationAlgorithm);

        // Request timeout and delivery timeout
        props.put(ProducerConfig.REQUEST_TIMEOUT_MS_CONFIG, 30000);
        props.put(ProducerConfig.DELIVERY_TIMEOUT_MS_CONFIG, 120000);

        return new KafkaProducer<>(props);
    }
}

// ==================== Header Validation & Sanitization ====================

class HeaderValidator {

    // Allowed header key pattern: alphanumeric, hyphens, underscores
    private static final Pattern ALLOWED_HEADER_KEY_PATTERN = Pattern.compile("^[a-zA-Z0-9_-]{1,128}$");

    // Maximum header value length in bytes
    private static final int MAX_HEADER_VALUE_BYTES = 4096;

    // Maximum number of custom headers per message
    private static final int MAX_CUSTOM_HEADERS = 20;

    // Maximum total headers size in bytes
    private static final int MAX_TOTAL_HEADERS_BYTES = 32768;

    // Allowlist of permitted header keys (configurable)
    private static final Set<String> ALLOWED_HEADER_KEYS = Set.of(
            "tracking-id",
            "user-id",
            "correlation-id",
            "session-id",
            "event-type",
            "event-source",
            "event-version",
            "content-type",
            "timestamp",
            "region",
            "environment",
            "client-version",
            "device-type",
            "request-id",
            "tenant-id",
            "trace-id",
            "span-id",
            "priority",
            "category",
            "tags"
    );

    // Blocked header keys that could interfere with Kafka internals
    private static final Set<String> BLOCKED_HEADER_KEYS = Set.of(
            "__producer_id",
            "__transaction_id",
            "__key",
            "__topic",
            "__partition",
            "__offset",
            "__timestamp"
    );

    public static ValidationResult validateHeaders(Map<String, String> headers) {
        if (headers == null || headers.isEmpty()) {
            return ValidationResult.success();
        }

        if (headers.size() > MAX_CUSTOM_HEADERS) {
            return ValidationResult.failure(
                    String.format("Too many headers: %d. Maximum allowed: %d", headers.size(), MAX_CUSTOM_HEADERS));
        }

        int totalBytes = 0;
        List<String> errors = new ArrayList<>();

        for (Map.Entry<String, String> entry : headers.entrySet()) {
            String key = entry.getKey();
            String value = entry.getValue();

            // Validate key format
            if (key == null || !ALLOWED_HEADER_KEY_PATTERN.matcher(key).matches()) {
                errors.add(String.format("Invalid header key format: '%s'. Must match pattern: %s",
                        key, ALLOWED_HEADER_KEY_PATTERN.pattern()));
                continue;
            }

            // Check against blocked keys
            if (BLOCKED_HEADER_KEYS.contains(key.toLowerCase())) {
                errors.add(String.format("Header key '%s' is reserved and cannot be used", key));
                continue;
            }

            // Check against allowlist
            if (!ALLOWED_HEADER_KEYS.contains(key.toLowerCase())) {
                errors.add(String.format("Header key '%s' is not in the allowed list", key));
                continue;
            }

            // Validate value
            if (value == null) {
                errors.add(String.format("Header value for key '%s' cannot be null", key));
                continue;
            }

            byte[] valueBytes = value.getBytes(StandardCharsets.UTF_8);
            if (valueBytes.length > MAX_HEADER_VALUE_BYTES) {
                errors.add(String.format("Header value for key '%s' exceeds max size: %d bytes (max: %d)",
                        key, valueBytes.length, MAX_HEADER_VALUE_BYTES));
                continue;
            }

            // Check for control characters and injection attempts
            if (containsControlCharacters(value)) {
                errors.add(String.format("Header value for key '%s' contains invalid control characters", key));
                continue;
            }

            totalBytes += key.getBytes(StandardCharsets.UTF_8).length + valueBytes.length;
        }

        if (totalBytes > MAX_TOTAL_HEADERS_BYTES) {
            errors.add(String.format("Total headers size %d bytes exceeds maximum %d bytes",
                    totalBytes, MAX_TOTAL_HEADERS_BYTES));
        }

        if (!errors.isEmpty()) {
            return ValidationResult.failure(String.join("; ", errors));
        }

        return ValidationResult.success();
    }

    public static String sanitizeHeaderValue(String value) {
        if (value == null) {
            return "";
        }
        // Remove control characters except common whitespace
        return value.replaceAll("[\\x00-\\x08\\x0B\\x0C\\x0E-\\x1F\\x7F]", "").trim();
    }

    private static boolean containsControlCharacters(String value) {
        for (char c : value.toCharArray()) {
            if (c < 0x20 && c != '\t' && c != '\n' && c != '\r') {
                return true;
            }
            if (c == 0x7F) {
                return true;
            }
        }
        return false;
    }
}

class ValidationResult {
    private final boolean valid;
    private final String errorMessage;

    private ValidationResult(boolean valid, String errorMessage) {
        this.valid = valid;
        this.errorMessage = errorMessage;
    }

    public static ValidationResult success() {
        return new ValidationResult(true, null);
    }

    public static ValidationResult failure(String errorMessage) {
        return new ValidationResult(false, errorMessage);
    }

    public boolean isValid() {
        return valid;
    }

    public String getErrorMessage() {
        return errorMessage;
    }
}

