// ==================== Kafka Producer Service ====================

@org.springframework.stereotype.Service
class EventProducerService {

    private static final org.slf4j.Logger logger = org.slf4j.LoggerFactory.getLogger(EventProducerService.class);

    // Allowed topics (whitelist to prevent unauthorized topic access)
    private static final Set<String> ALLOWED_TOPICS = Set.of(
            "event-tracking",
            "user-events",
            "system-events",
            "audit-events",
            "analytics-events"
    );

    private static final Pattern TOPIC_PATTERN = Pattern.compile("^[a-zA-Z0-9._-]{1,249}$");
    private static final int MAX_MESSAGE_VALUE_BYTES = 1048576; // 1MB

    private final KafkaProducer<String, String> kafkaProducer;

    @Autowired
    public EventProducerService(KafkaProducer<String, String> kafkaProducer) {
        this.kafkaProducer = kafkaProducer;
    }

    public EventResponse sendEvent(EventMessage eventMessage, Map<String, String> httpHeaders) {
        EventResponse response = new EventResponse();

        try {
            // Validate topic
            String topic = eventMessage.getTopic();
            if (topic == null || !TOPIC_PATTERN.matcher(topic).matches()) {
                response.setStatus("ERROR");
                response.setErrorMessage("Invalid topic name format");
                return response;
            }

            if (!ALLOWED_TOPICS.contains(topic)) {
                response.setStatus("ERROR");
                response.setErrorMessage("Topic not in allowed list: " + topic);
                return response;
            }

            // Validate message value
            if (eventMessage.getValue() == null || eventMessage.getValue().isEmpty()) {
                response.setStatus("ERROR");
                response.setErrorMessage("Message value cannot be null or empty");
                return response;
            }

            byte[] valueBytes = eventMessage.getValue().getBytes(StandardCharsets.UTF_8);
            if (valueBytes.length > MAX_MESSAGE_VALUE_BYTES) {
                response.setStatus("ERROR");
                response.setErrorMessage(String.format("Message value exceeds max size: %d bytes (max: %d)",
                        valueBytes.length, MAX_MESSAGE_VALUE_BYTES));
                return response;
            }

            // Merge and validate headers from body and HTTP request
            Map<String, String> mergedHeaders = mergeHeaders(eventMessage.getHeaders(), httpHeaders);

            ValidationResult validationResult = HeaderValidator.validateHeaders(mergedHeaders);
            if (!validationResult.isValid()) {
                response.setStatus("ERROR");
                response.setErrorMessage("Header validation failed: " + validationResult.getErrorMessage());
                return response;
            }

            // Sanitize key
            String key = eventMessage.getKey();
            if (key != null) {
                key = sanitizeKey(key);
            }

            // Build ProducerRecord
            ProducerRecord<String, String> record;
            if (eventMessage.getPartition() != null) {
                record = new ProducerRecord<>(topic, eventMessage.getPartition(), key, eventMessage.getValue());
            } else {
                record = new ProducerRecord<>(topic, key, eventMessage.getValue());
            }

            // Add validated and sanitized headers
            Map<String, String> appliedHeaders = new LinkedHashMap<>();
            if (mergedHeaders != null && !mergedHeaders.isEmpty()) {
                for (Map.Entry<String, String> entry : mergedHeaders.entrySet()) {
                    String headerKey = entry.getKey().toLowerCase();
                    String headerValue = HeaderValidator.sanitizeHeaderValue(entry.getValue());
                    record.headers().add(new RecordHeader(headerKey, headerValue.getBytes(StandardCharsets.UTF_8)));
                    appliedHeaders.put(headerKey, headerValue);
                }
            }

            // Add system headers (non-user-controllable)
            String messageId = UUID.randomUUID().toString();
            record.headers().add(new RecordHeader("x-message-id",
                    messageId.getBytes(StandardCharsets.UTF_8)));
            record.headers().add(new RecordHeader("x-produced-at",
                    String.valueOf(System.currentTimeMillis()).getBytes(StandardCharsets.UTF_8)));
            record.headers().add(new RecordHeader("x-producer-version",
                    "1.0.0".getBytes(StandardCharsets.UTF_8)));

            appliedHeaders.put("x-message-id", messageId);

            // Send synchronously with timeout
            Future<RecordMetadata> future = kafkaProducer.send(record, (metadata, exception) -> {
                if (exception != null) {
                    logger.error("Failed to send message to topic {}: {}", topic, exception.getMessage(), exception);
                } else {
                    logger.info("Message sent successfully to topic={}, partition={}, offset={}",
                            metadata.topic(), metadata.partition(), metadata.offset());
                }
            });

            RecordMetadata metadata = future.get(30, TimeUnit.SECONDS);

            response.setStatus("SUCCESS");
            response.setTopic(metadata.topic());
            response.setPartition(metadata.partition());
            response.setOffset(metadata.offset());
            response.setTimestamp(metadata.timestamp());
            response.setAppliedHeaders(appliedHeaders);

            logger.info("Event published: topic={}, partition={}, offset={}, messageId={}",
                    metadata.topic(), metadata.partition(), metadata.offset(), messageId);

        } catch (Exception e) {
            logger.error("Error sending event: {}", e.getMessage(), e);
            response.setStatus("ERROR");
            response.setErrorMessage("Failed to send event: " + e.getMessage());
        }

        return response;
    }

    /**
     * Merge headers from the request body and relevant HTTP headers.
     * Body headers take precedence over HTTP headers.
     */
    private Map<String, String> mergeHeaders(Map<String, String> bodyHeaders, Map<String, String> httpHeaders) {
        Map<String, String> merged = new LinkedHashMap<>();

        // Extract relevant HTTP headers (with x-event- prefix)
        if (httpHeaders != null) {
            for (Map.Entry<String, String> entry : httpHeaders.entrySet()) {
                String key = entry.getKey().toLowerCase();
                if (key.startsWith("x-event-")) {
                    // Strip the x-event- prefix for the Kafka header
                    String kafkaHeaderKey = key.substring("x-event-".length());
                    merged.put(kafkaHeaderKey, entry.getValue());
                }
                // Also accept standard tracking headers directly
                if (key.equals("tracking-id") || key.equals("correlation-id") ||
                        key.equals("request-id") || key.equals("trace-id") || key.equals("span-id")) {
                    merged.put(key, entry.getValue());
                }
            }
        }

        // Body headers override HTTP headers
        if (bodyHeaders != null) {
            merged.putAll(bodyHeaders);
        }

        return merged;
    }

    private String sanitizeKey(String key) {
        if (key.length() > 256) {
            key = key.substring(0, 256);
        }
        // Remove control characters
        return key.replaceAll("[\\x00-\\x1F\\x7F]", "");
    }

    @PreDestroy
    public void shutdown() {
        logger.info("Shutting down Kafka producer...");
        if (kafkaProducer != null) {
            kafkaProducer.flush();
            kafkaProducer.close(java.time.Duration.ofSeconds(10));
        }
        logger.info("Kafka producer shut down successfully");
    }
}

// ==================== REST Controller ====================

@RestController
@RequestMapping("/api/v1/events")
class EventController {

    private static final org.slf4j.Logger logger = org.slf4j.LoggerFactory.getLogger(EventController.class);

    private final EventProducerService eventProducerService;

    @Autowired
    public EventController(EventProducerService eventProducerService) {
        this.eventProducerService = eventProducerService;
    }

    /**
     * Send a single event with custom headers.
     *
     * Headers can be provided in two ways:
     * 1. In the request body under "headers" field
     * 2. As HTTP headers with "x-event-" prefix (e.g., x-event-tracking-id)
     *
     * Standard tracking headers (tracking-id, correlation-id, request-id, trace-id, span-id)
     * are also extracted from HTTP headers automatically.
     */
    @PostMapping("/publish")
    public ResponseEntity<EventResponse> publishEvent(
            @RequestBody EventMessage eventMessage,
            @RequestHeader Map<String, String> httpHeaders) {

        logger.info("Received event publish request for topic: {}", eventMessage.getTopic());

        EventResponse response = eventProducerService.sendEvent(eventMessage, httpHeaders);

        if ("SUCCESS".equals(response.getStatus())) {
            return ResponseEntity.ok(response);
        } else {
            return ResponseEntity.status(HttpStatus.BAD_REQUEST).body(response);
        }
    }

    /**
     * Send multiple events in a batch.
     */
    @PostMapping("/publish/batch")
    public ResponseEntity<List<EventResponse>> publishBatch(
            @RequestBody List<EventMessage> eventMessages,
            @RequestHeader Map<String, String> httpHeaders) {

        if (eventMessages == null || eventMessages.isEmpty()) {
            EventResponse errorResponse = new EventResponse();
            errorResponse.setStatus("ERROR");
            errorResponse.setErrorMessage("Batch cannot be empty");
            return ResponseEntity.badRequest().body(Collections.singletonList(errorResponse));
        }

        if (eventMessages.size() > 100) {
            EventResponse errorResponse = new EventResponse();
            errorResponse.setStatus("ERROR");
            errorResponse.setErrorMessage("Batch size exceeds maximum of 100 messages");
            return ResponseEntity.badRequest().body(Collections.singletonList(errorResponse));
        }

        logger.info("Received batch publish request with {} events", eventMessages.size());

        List<EventResponse> responses = new ArrayList<>();
        for (EventMessage eventMessage : eventMessages) {
            EventResponse response = eventProducerService.sendEvent(eventMessage, httpHeaders);
            responses.add(response);
        }

        boolean allSuccess = responses.stream().allMatch(r -> "SUCCESS".equals(r.getStatus()));
        boolean allFailed = responses.stream().allMatch(r -> "ERROR".equals(r.getStatus()));

        if (allSuccess) {
            return ResponseEntity.ok(responses);
        } else if (allFailed) {
            return ResponseEntity.status(HttpStatus.BAD_REQUEST).body(responses);
        } else {
            // Partial success
            return ResponseEntity.status(HttpStatus.MULTI_STATUS).body(responses);
        }
    }

    /**
     * Health check endpoint.
     */
    @GetMapping("/health")
    public ResponseEntity<Map<String, String>> health() {
        Map<String, String> status = new HashMap<>();
        status.put("status", "UP");
        status.put("service", "event-tracking-producer");
        status.put("timestamp", String.valueOf(System.currentTimeMillis()));
        return ResponseEntity.ok(status);
    }
}